import React from "react";
import styles from "./cart-wrapper.module.css";
import TableHeading from "../table-heading";
import CartItem from "../cart-item";
import CartSubtotal from "../cart-subtotal";
import Button from "../../button";
import products from "../../homepage/product-listing/product.json";

import { useAppSelector } from "../../../app/hooks";

const CartWrapper = () => {

  const cart = useAppSelector((state: RootState) => state.cart);

  return (
    <div className={styles.cart_wrapper}>
      <div className="container">
        <div className="cart_top">
          <TableHeading col1="Product" col2="Price" col3="Quantity" col4="Total" />
        </div>
        <div className="cart_body">
          {products.map((product) => (
            <CartItem 
            key={product.id}
            id={product.id}
            imgSrc={product.img}
            title={product.name}
            price={product.price}
            total={product.total}
           />
          ))}
        </div>
        <div className={styles.cart_bottom}>
            <CartSubtotal title="Sub-total" price={9.99} VAT="Tax and shipping cost will be calculated later"/>
            <Button text="Check-out" to="/checkout" />
        </div>
      </div>
    </div>
  );
};

export default CartWrapper;
